    const int MOD = 1e9 + 7;
    const int MAX_VAL = 5000;
    const int MAX_DIGIT_SUM = 50; // Max allowed in input, though max achievable is 31

    int N = digitSum.size();

    // Step 1: Precalculate P[D] - list of numbers <= 5000 with digit sum D
    vector<vector<int>> P(MAX_DIGIT_SUM + 1);
    for (int x = 0; x <= MAX_VAL; ++x) {
        int d = sum_digits(x);
        if (d <= MAX_DIGIT_SUM) {
            P[d].push_back(x);
        }
    }

    // Step 2: Dynamic Programming
    // dp_prev[j]: Number of valid prefixes ending in j (for previous step)
    // dp_curr[j]: Number of valid prefixes ending in j (for current step)

    // Size needs to be MAX_VAL + 1 = 5001
    vector<long long> dp_prev(MAX_VAL + 1, 0);

    // Initialization (i = 0)
    int D0 = (int)digitSum[0];
    if (D0 <= MAX_DIGIT_SUM) {
        for (int j : P[D0]) {
            dp_prev[j] = 1;
        }
    } else {
        // If D0 is too large, no valid array exists
        return 0;
    }

    // DP Iteration (i = 1 to N-1)
    for (int i = 1; i < N; ++i) {
        vector<long long> dp_curr(MAX_VAL + 1, 0);
        int D_curr = (int)digitSum[i];

        if (D_curr > MAX_DIGIT_SUM || P[D_curr].empty()) {
            // If the required digit sum D_curr is impossible to achieve in [0, 5000]
            return 0;
