            // Step 1: Calculate Prefix Sums of dp_prev
            // P_prev[v] = sum(dp_prev[u] for u=0 to v)
            std::vector<int> P_prev(V_MAX + 1, 0);
            P_prev[0] = dp_prev[0];
            for (int v = 1; v <= V_MAX; ++v) {
                P_prev[v] = (P_prev[v - 1] + dp_prev[v]) % MOD;
            }

            // Step 2: Calculate dp_curr
            // dp_curr[v] = P_prev[v] if sum_digits(v) == target_si
            for (int v = 0; v <= V_MAX; ++v) {
                if (sums[v] == target_si) {
                    // The number of ways to reach v is the total count of valid previous numbers u <= v
                    dp_curr[v] = P_prev[v];
                }
            }

            // Update for next iteration
            dp_prev = dp_curr;
        }

        // Final Result: Sum up all counts in the final DP state
        long long total_count = 0;
        for (int v = 0; v <= V_MAX; ++v) {
            total_count = (total_count + dp_prev[v]) % MOD;
        }

        return total_count;
    }
};
